const amqp = require('amqplib');
const { exec } = require('child_process');

// Configuration
const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const QUEUE_NAME = process.env.QUEUE_NAME || 'event_queue';
const PREFETCH_COUNT = parseInt(process.env.PREFETCH_COUNT || '1', 10); // Number of messages to prefetch

let connection;
let channel;

async function connectRabbitMQ() {
    try {
        connection = await amqp.connect(RABBITMQ_URL);
        connection.on('error', (err) => {
            console.error('[AMQP] connection error', err.message);
            // Attempt to reconnect after a delay
            setTimeout(connectRabbitMQ, 5000);
        });
        connection.on('close', () => {
            console.error('[AMQP] connection closed, attempting to reconnect...');
            setTimeout(connectRabbitMQ, 5000);
        });

        console.log('[AMQP] Connected to RabbitMQ');

        channel = await connection.createChannel();
        await channel.assertQueue(QUEUE_NAME, { durable: true });
        channel.prefetch(PREFETCH_COUNT);
        console.log(`[AMQP] Waiting for messages in ${QUEUE_NAME}. To exit press CTRL+C`);

        channel.consume(QUEUE_NAME, processMessage, { noAck: false });

    } catch (error) {
        console.error('[AMQP] Failed to connect or setup RabbitMQ:', error.message);
        setTimeout(connectRabbitMQ, 5000); // Retry connection
    }
}

async function processMessage(msg) {
    if (msg === null) {
        console.log('[AMQP] Consumer cancelled by server');
        return;
    }

    let messageContent;
    let originalMessage = msg.content.toString();

    try {
        messageContent = JSON.parse(originalMessage);
        console.log(`[AMQP] Received message: ${JSON.stringify(messageContent)}`);
    } catch (parseError) {
        console.error(`[AMQP] Error parsing message as JSON: ${parseError.message}. Content: ${originalMessage}`);
        channel.nack(msg, false, false); // Reject and do not requeue
        return;
    }

    const { type, payload } = messageContent;

    try {
        switch (type) {
            case 'user.created':
                await handleUserCreated(payload);
                break;
            case 'product.updated':
                await handleProductUpdated(payload);
                break;
            case 'system.command':
                await handleSystemCommand(payload);
                break;
            case 'log.event':
                await handleLogEvent(payload);
                break;
            default:
                console.warn(`[AMQP] Unknown message type: ${type}. Payload: ${JSON.stringify(payload)}`);
                break;
        }
        channel.ack(msg); // Acknowledge message only after successful processing
    } catch (processingError) {
        console.error(`[AMQP] Error processing message type ${type}: ${processingError.message}. Payload: ${JSON.stringify(payload)}`);
        // Optionally log full error stack
        console.error(processingError);
        // Nack the message, optionally requeue it.
        // Requeueing can lead to infinite loops if the error is persistent.
        // Consider dead-letter queues for robust error handling.
        channel.nack(msg, false, true); // Nack and requeue
    }
}

